 85→func TestSearchInput_Defaults(t *testing.T) {
 86→	t.Parallel()
 87→	// Verify that searchInput correctly serializes/deserializes.
 88→	raw := `{"filters":[{"field":"state","value":"\"CA\""}],"limit":5}`
 89→	var in searchInput
 90→	if err := json.Unmarshal([]byte(raw), &in); err != nil {
 91→		t.Fatalf("unmarshal: %v", err)
 92→	}
 93→	if len(in.Filters) != 1 {
 94→		t.Errorf("expected 1 filter, got %d", len(in.Filters))
 95→	}
 96→	if in.Filters[0].Field != "state" {
 97→		t.Errorf("expected field=state, got %q", in.Filters[0].Field)
 98→	}
 99→	if in.Limit != 5 {
100→		t.Errorf("expected limit=5, got %d", in.Limit)
101→	}
102→	if in.Offset != 0 {
103→		t.Errorf("expected offset=0, got %d", in.Offset)
104→	}
105→}
