111→func ptrFloat64(f float64) *float64 { return &f }
112→
113→func TestSearchHandler_NoFilters_Mock(t *testing.T) {
114→	t.Parallel()
115→	mock, err := pgxmock.NewPool()
116→	if err != nil {
117→		t.Fatalf("pgxmock.NewPool: %v", err)
118→	}
119→	defer mock.Close()
120→
121→	mock.ExpectQuery("SELECT COUNT").
122→		WillReturnRows(pgxmock.NewRows([]string{"count"}).AddRow(2))
123→
124→	mock.ExpectQuery("SELECT unit_id").
125→		WithArgs(search.DefaultLimit, 0).
126→		WillReturnRows(pgxmock.NewRows([]string{
127→			"unit_id", "institution_name", "city", "state", "latitude", "longitude",
128→			"distance", "my_price", "data", "blend_score",
129→		}).
130→			AddRow("100001", "University A", "Boston", "MA", ptrFloat64(42.0), ptrFloat64(-71.0), nil, nil, map[string]any{}, nil).
131→			AddRow("100002", "College B", "NYC", "NY", ptrFloat64(40.7), ptrFloat64(-74.0), nil, nil, map[string]any{}, nil))
132→
133→	registry := search.NewRegistry()
134→	handler := makeSearchHandler(mock, registry)
135→
136→	result, _, err := handler(context.Background(), nil, searchInput{})
137→	if err != nil {
138→		t.Fatalf("search: %v", err)
139→	}
140→
141→	text := result.Content[0].(*mcp.TextContent)
142→	var resp search.SearchResponse
143→	if err := json.Unmarshal([]byte(text.Text), &resp); err != nil {
144→		t.Fatalf("unmarshal: %v", err)
145→	}
146→	if resp.Total != 2 {
147→		t.Errorf("Total = %d, want 2", resp.Total)
148→	}
149→	if len(resp.Results) != 2 {
150→		t.Errorf("len(Results) = %d, want 2", len(resp.Results))
151→	}
152→	if resp.Limit != search.DefaultLimit {
153→		t.Errorf("Limit = %d, want %d", resp.Limit, search.DefaultLimit)
154→	}
155→
156→	if err := mock.ExpectationsWereMet(); err != nil {
157→		t.Errorf("unmet expectations: %v", err)
158→	}
159→}
