307→func TestDetailHandler_NotFound_Mock(t *testing.T) {
308→	t.Parallel()
309→	mock, err := pgxmock.NewPool()
310→	if err != nil {
311→		t.Fatalf("pgxmock.NewPool: %v", err)
312→	}
313→	defer mock.Close()
314→
315→	mock.ExpectQuery("SELECT unit_id").
316→		WithArgs("999999").
317→		WillReturnError(pgx.ErrNoRows)
318→
319→	handler := makeDetailHandler(mock)
320→	result, _, err := handler(context.Background(), nil, detailInput{UnitID: "999999"})
