  8→// BuildQuery builds a parameterised SELECT query against search_base.dataset_merged.
  9→// It selects the core result columns plus computed distance and myPrice columns,
 10→// applies WHERE clauses for the request's filters, and appends ORDER BY / LIMIT / OFFSET.
 11→func BuildQuery(reg *Registry, req SearchRequest) (sql string, args []any, err error) {
 12→	clauses, args, err := buildWhere(reg, req.Filters)
 13→	if err != nil {
 14→		return "", nil, err
 15→	}
 16→
 17→	argStart := len(args) + 1
 18→
 19→	// Always select 10 columns so Scan is uniform.
 20→	distanceExpr := "NULL::double precision"
 21→	myPriceExpr := "NULL::integer"
 22→	blendExpr := "NULL::double precision"
 23→
 24→	if req.UserLocation != nil {
 25→		// Distance in miles via PostGIS geography.
 26→		distanceExpr = fmt.Sprintf(
 27→			"ST_Distance(coordinates, ST_SetSRID(ST_MakePoint($%d, $%d), 4326)::geography) / 1609.344",
 28→			argStart, argStart+1,
 29→		)
 30→		args = append(args, req.UserLocation.Longitude, req.UserLocation.Latitude)
 31→		argStart += 2
 32→
 33→		if req.UserLocation.State != "" {
 34→			myPriceExpr = fmt.Sprintf(
 35→				"CASE WHEN state = $%d THEN (data #>> '{nces,tuition_in_state}')::integer "+
 36→					"ELSE (data #>> '{nces,tuition_out_of_state}')::integer END",
 37→				argStart,
 38→			)
 39→			args = append(args, req.UserLocation.State)
 40→			argStart++
 41→		}
 42→	}
 43→
 44→	if req.Blend != nil {
 45→		expr, berr := buildBlendExpression(reg, req.Blend)
 46→		if berr != nil {
 47→			return "", nil, berr
 48→		}
 49→		blendExpr = expr
 50→	}
 51→
 52→	q := fmt.Sprintf(
 53→		"SELECT unit_id, institution_name, city, state, latitude, longitude, %s, %s, data, %s AS blend_score FROM search_base.dataset_merged",
 54→		distanceExpr, myPriceExpr, blendExpr,
 55→	)
 56→	if len(clauses) > 0 {
 57→		q += " WHERE " + strings.Join(clauses, " AND ")
 58→	}
 59→
 60→	// ORDER BY: when blend is active and no explicit sort, default to blend score.
 61→	// When an explicit sort is provided, honour it even with blend active.
 62→	if req.Blend != nil && req.Sort == nil {
 63→		q += " ORDER BY 10 ASC NULLS LAST"
 64→	} else {
 65→		orderBy, err := buildOrderBy(reg, req)
 66→		if err != nil {
 67→			return "", nil, err
 68→		}
 69→		q += orderBy
 70→	}
 71→
 72→	limit := req.Limit
 73→	if limit <= 0 {
 74→		limit = DefaultLimit
 75→	}
 76→	if limit > MaxLimit {
 77→		limit = MaxLimit
 78→	}
 79→	offset := req.Offset
 80→	if offset < 0 {
 81→		offset = 0
 82→	}
 83→	if offset+limit > MaxLimit {
 84→		offset = MaxLimit - limit
 85→		if offset < 0 {
 86→			offset = 0
 87→		}
 88→	}
 89→	q += fmt.Sprintf(" LIMIT $%d OFFSET $%d", argStart, argStart+1)
 90→	args = append(args, limit, offset)
 91→
 92→	return q, args, nil
 93→}
