 95→// buildOrderBy returns an ORDER BY clause based on the sort input.
 96→// It handles the built-in DISTANCE and NAME sorts as special cases, and looks
 97→// up any other field name in the registry to generate a column or JSONB sort.
 98→func buildOrderBy(reg *Registry, req SearchRequest) (string, error) {
 99→	if req.Sort == nil {
100→		return " ORDER BY institution_name ASC", nil
101→	}
102→
103→	dir := "ASC"
104→	if req.Sort.Direction == SortDirectionDesc {
105→		dir = "DESC"
106→	}
107→
108→	nulls := "NULLS LAST"
109→	if dir == "DESC" {
110→		nulls = "NULLS FIRST"
111→	}
112→
113→	switch req.Sort.Field {
114→	case "distance":
115→		// Column 7 is the distance expression.
116→		return fmt.Sprintf(" ORDER BY 7 %s %s", dir, nulls), nil
117→	case "name":
118→		return fmt.Sprintf(" ORDER BY institution_name %s", dir), nil
119→	case "blend_score":
120→		// Column 10 is the blend score expression.
121→		return fmt.Sprintf(" ORDER BY 10 %s %s", dir, nulls), nil
122→	}
123→
124→	// Look up field in registry.
125→	field, ok := reg.Lookup(req.Sort.Field)
126→	if !ok {
127→		return "", fmt.Errorf("search: unknown sort field %q", req.Sort.Field)
128→	}
129→	if !field.Descriptor().Sortable {
130→		return "", fmt.Errorf("search: field %q is not sortable", req.Sort.Field)
131→	}
132→
133→	src := field.Source()
134→	switch src.Kind {
135→	case SourceColumn:
136→		return fmt.Sprintf(" ORDER BY %s %s %s", src.Column, dir, nulls), nil
137→	case SourceJSONBPath:
138→		castType := sqlCastType(src.ValueType)
139→		return fmt.Sprintf(" ORDER BY (%s)::%s %s %s", src.SQLRef(), castType, dir, nulls), nil
140→	default:
141→		return "", fmt.Errorf("search: field %q has unsortable source kind %q", req.Sort.Field, src.Kind)
142→	}
143→}
