145→// BuildCountQuery builds a COUNT(*) query with the same WHERE clauses as BuildQuery
146→// but without LIMIT / OFFSET. Used to compute the total result count.
147→func BuildCountQuery(reg *Registry, req SearchRequest) (sql string, args []any, err error) {
148→	clauses, args, err := buildWhere(reg, req.Filters)
149→	if err != nil {
150→		return "", nil, err
151→	}
152→
153→	q := "SELECT COUNT(*) FROM search_base.dataset_merged"
154→	if len(clauses) > 0 {
155→		q += " WHERE " + strings.Join(clauses, " AND ")
156→	}
157→
158→	return q, args, nil
159→}
