162→// BuildExportQuery builds a parameterised SELECT query for CSV export.
163→// It is similar to BuildQuery but has no offset and caps the limit to maxRows
164→// instead of MaxLimit.
165→func BuildExportQuery(reg *Registry, req SearchRequest, maxRows int) (sql string, args []any, err error) {
166→	clauses, args, err := buildWhere(reg, req.Filters)
167→	if err != nil {
168→		return "", nil, err
169→	}
170→
171→	argStart := len(args) + 1
172→
173→	// Always select 10 columns so Scan is uniform.
174→	distanceExpr := "NULL::double precision"
175→	myPriceExpr := "NULL::integer"
176→	blendExpr := "NULL::double precision"
177→
178→	if req.UserLocation != nil {
179→		distanceExpr = fmt.Sprintf(
180→			"ST_Distance(coordinates, ST_SetSRID(ST_MakePoint($%d, $%d), 4326)::geography) / 1609.344",
181→			argStart, argStart+1,
182→		)
183→		args = append(args, req.UserLocation.Longitude, req.UserLocation.Latitude)
184→		argStart += 2
185→
186→		if req.UserLocation.State != "" {
187→			myPriceExpr = fmt.Sprintf(
188→				"CASE WHEN state = $%d THEN (data #>> '{nces,tuition_in_state}')::integer "+
189→					"ELSE (data #>> '{nces,tuition_out_of_state}')::integer END",
190→				argStart,
191→			)
192→			args = append(args, req.UserLocation.State)
193→			argStart++
194→		}
195→	}
196→
197→	if req.Blend != nil {
198→		expr, berr := buildBlendExpression(reg, req.Blend)
199→		if berr != nil {
200→			return "", nil, berr
201→		}
202→		blendExpr = expr
203→	}
204→
205→	q := fmt.Sprintf(
206→		"SELECT unit_id, institution_name, city, state, latitude, longitude, %s, %s, data, %s AS blend_score FROM search_base.dataset_merged",
207→		distanceExpr, myPriceExpr, blendExpr,
208→	)
209→	if len(clauses) > 0 {
210→		q += " WHERE " + strings.Join(clauses, " AND ")
211→	}
212→
213→	if req.Blend != nil && req.Sort == nil {
214→		q += " ORDER BY 10 ASC NULLS LAST"
215→	} else {
216→		orderBy, err := buildOrderBy(reg, req)
217→		if err != nil {
218→			return "", nil, err
219→		}
220→		q += orderBy
221→	}
222→
223→	limit := req.Limit
224→	if limit <= 0 {
225→		limit = DefaultLimit
226→	}
227→	if limit > maxRows {
228→		limit = maxRows
229→	}
230→	q += fmt.Sprintf(" LIMIT $%d", argStart)
231→	args = append(args, limit)
232→
233→	return q, args, nil
234→}
235→
236→// permanentFilter is an unconditional WHERE clause applied to every query.
237→// It excludes non-degree-granting locations (0), certificate-only programs (1),
238→// and associate's-only institutions (2), keeping only Bachelor's or higher (≥ 3).
239→const permanentFilter = "COALESCE((data #>> '{nces,degrees_awarded_highest}')::int, 0) >= 3"
240→
241→// buildWhere resolves each FilterInput to a SQL clause, advancing the placeholder
242→// index across filters so that $N numbering is globally consistent within one query.
243→func buildWhere(reg *Registry, filters []FilterInput) (clauses []string, args []any, err error) {
244→	clauses = []string{permanentFilter}
245→	argStart := 1
246→	for _, fi := range filters {
247→		field, ok := reg.Lookup(fi.Field)
248→		if !ok {
249→			return nil, nil, fmt.Errorf("unknown field %q", fi.Field)
250→		}
251→		clause, fieldArgs, ferr := field.BuildSQL(fi.Value, argStart)
252→		if ferr != nil {
253→			return nil, nil, fmt.Errorf("field %q: %w", fi.Field, ferr)
254→		}
255→		clauses = append(clauses, clause)
256→		args = append(args, fieldArgs...)
257→		argStart += len(fieldArgs)
258→	}
259→	return clauses, args, nil
260→}
