			json.RawMessage(`{"key":"value"}`),
		))

	handler := makeDetailHandler(mock)
	result, _, err := handler(context.Background(), nil, detailInput{UnitID: "123456"})
	if err != nil {
		t.Fatalf("detail: %v", err)
	}
	if result.IsError {
		t.Error("unexpected error result")
	}

	text := result.Content[0].(*mcp.TextContent)
	var detail map[string]any
	if err := json.Unmarshal([]byte(text.Text), &detail); err != nil {
		t.Fatalf("unmarshal: %v", err)
	}
	if detail["unit_id"] != "123456" {
		t.Errorf("unit_id = %v, want %q", detail["unit_id"], "123456")
	}
	if detail["institution_name"] != "Test University" {
		t.Errorf("institution_name = %v, want %q", detail["institution_name"], "Test University")
	}

	if err := mock.ExpectationsWereMet(); err != nil {
		t.Errorf("unmet expectations: %v", err)
	}
}

func TestDetailHandler_NotFound_Mock(t *testing.T) {
	t.Parallel()
	mock, err := pgxmock.NewPool()
	if err != nil {
		t.Fatalf("pgxmock.NewPool: %v", err)
	}
	defer mock.Close()

	mock.ExpectQuery("SELECT unit_id").
		WithArgs("999999").
		WillReturnError(pgx.ErrNoRows)

	handler := makeDetailHandler(mock)
	result, _, err := handler(context.Background(), nil, detailInput{UnitID: "999999"})
	if err != nil {
		t.Fatalf("detail: %v", err)
	}
	if !result.IsError {
		t.Error("expected IsError=true for not-found institution")
	}

	text := result.Content[0].(*mcp.TextContent)
	if !strings.Contains(text.Text, "not found") {
		t.Errorf("expected not-found message, got: %s", text.Text)
	}

	if err := mock.ExpectationsWereMet(); err != nil {
		t.Errorf("unmet expectations: %v", err)
	}
}

func TestDetailHandler_QueryError_Mock(t *testing.T) {
	t.Parallel()
	mock, err := pgxmock.NewPool()
	if err != nil {
		t.Fatalf("pgxmock.NewPool: %v", err)
	}
	defer mock.Close()

	mock.ExpectQuery("SELECT unit_id").
		WithArgs("123456").
		WillReturnError(fmt.Errorf("connection refused"))

	handler := makeDetailHandler(mock)
