	if err := mock.ExpectationsWereMet(); err != nil {
		t.Errorf("unmet expectations: %v", err)
	}
}

func TestDetailHandler_QueryError_Mock(t *testing.T) {
	t.Parallel()
	mock, err := pgxmock.NewPool()
	if err != nil {
		t.Fatalf("pgxmock.NewPool: %v", err)
	}
	defer mock.Close()

	mock.ExpectQuery("SELECT unit_id").
		WithArgs("123456").
		WillReturnError(fmt.Errorf("connection refused"))

	handler := makeDetailHandler(mock)
	_, _, err = handler(context.Background(), nil, detailInput{UnitID: "123456"})
	if err == nil {
		t.Fatal("expected error when query fails")
	}
	if !strings.Contains(err.Error(), "detail query") {
		t.Errorf("error should mention detail query, got: %v", err)
	}

	if err := mock.ExpectationsWereMet(); err != nil {
		t.Errorf("unmet expectations: %v", err)
	}
}

