func connectTestDB(t *testing.T) *pgxpool.Pool {
	t.Helper()
	if testing.Short() {
		t.Skip("integration test")
	}
	dsn := os.Getenv("DATABASE_URL")
	if dsn == "" {
		t.Skip("DATABASE_URL not set")
	}
	pool, err := pgxpool.New(context.Background(), dsn)
	if err != nil {
		t.Fatalf("connect: %v", err)
	}
	t.Cleanup(pool.Close)
	return pool
}

func TestIntegrationSearchColleges(t *testing.T) {
	pool := connectTestDB(t)
	registry := search.NewRegistry()
	handler := makeSearchHandler(pool, registry)

	// Search with no filters — should return results.
	result, _, err := handler(context.Background(), nil, searchInput{})
	if err != nil {
		t.Fatalf("search: %v", err)
	}

	text, ok := result.Content[0].(*mcp.TextContent)
	if !ok {
		t.Fatalf("expected TextContent, got %T", result.Content[0])
	}

	var resp search.SearchResponse
	if err := json.Unmarshal([]byte(text.Text), &resp); err != nil {
		t.Fatalf("unmarshal: %v", err)
	}
	if resp.Total == 0 {
		t.Error("expected non-zero total")
	}
	if len(resp.Results) == 0 {
		t.Error("expected non-empty results")
	}
	if resp.Limit != search.DefaultLimit {
		t.Errorf("expected default limit %d, got %d", search.DefaultLimit, resp.Limit)
	}
}

func TestIntegrationSearchCollegesWithFilter(t *testing.T) {
	pool := connectTestDB(t)
	registry := search.NewRegistry()
	handler := makeSearchHandler(pool, registry)

	result, _, err := handler(context.Background(), nil, searchInput{
		Filters: []search.FilterInput{
			{Field: "state", Value: json.RawMessage(`["CA"]`)},
		},
		Limit: 5,
	})
	if err != nil {
		t.Fatalf("search: %v", err)
	}

	text := result.Content[0].(*mcp.TextContent)
	var resp search.SearchResponse
	if err := json.Unmarshal([]byte(text.Text), &resp); err != nil {
		t.Fatalf("unmarshal: %v", err)
	}
	if resp.Total == 0 {
		t.Error("expected California colleges")
	}
	if len(resp.Results) > 5 {
		t.Errorf("expected at most 5 results, got %d", len(resp.Results))
	}
	for _, r := range resp.Results {
		if r.State != "CA" {
			t.Errorf("expected state=CA, got %q", r.State)
		}
	}
}

func TestIntegrationGetCollegeDetail(t *testing.T) {
	pool := connectTestDB(t)
	handler := makeDetailHandler(pool)

	// First, find a valid unit_id from the database.
	var unitID string
	err := pool.QueryRow(context.Background(),
		"SELECT unit_id FROM search_base.dataset_merged LIMIT 1",
	).Scan(&unitID)
	if err != nil {
		t.Fatalf("find unit_id: %v", err)
	}

	result, _, err := handler(context.Background(), nil, detailInput{UnitID: unitID})
	if err != nil {
		t.Fatalf("detail: %v", err)
	}
	if result.IsError {
		t.Errorf("unexpected error result: %v", result.Content)
	}

	text := result.Content[0].(*mcp.TextContent)
	var detail map[string]any
	if err := json.Unmarshal([]byte(text.Text), &detail); err != nil {
		t.Fatalf("unmarshal: %v", err)
	}
	if detail["unit_id"] != unitID {
		t.Errorf("expected unit_id=%q, got %q", unitID, detail["unit_id"])
	}
	if detail["institution_name"] == nil || detail["institution_name"] == "" {
		t.Error("expected non-empty institution_name")
	}
}

func TestIntegrationGetCollegeDetail_NotFound(t *testing.T) {
	pool := connectTestDB(t)
	handler := makeDetailHandler(pool)

	result, _, err := handler(context.Background(), nil, detailInput{UnitID: "999999999"})
	if err != nil {
		t.Fatalf("detail: %v", err)
	}
	if !result.IsError {
		t.Error("expected IsError=true for non-existent institution")
	}
}

